{"code": "import json
result_file = locals()['var_functions.query_db:2']
with open(result_file, 'r') as f:
    articles_data = json.load(f)

# Simple and direct approach - find Olympic/sports articles
sports_articles = []

for article in articles_data:
    title = article.get('title', '').lower()
    desc = article.get('description', '').lower()
    description = article.get('description', '')
    full_text = title + ' ' + desc

    # Look for Olympic Games specifically
    if 'olympic' in full_text or 'olympics' in full_text:
        sports_articles.append({
            'title': article.get('title'),
            'description': description,
            'desc_length': len(description)
        })
    # Look for "games" in athletic context
    elif 'games' in full_text:
        # Check if it's about Olympic Games or similar
        athletic_indicators = ['athens', 'greece', 'olympia', 'competition', 'athlete', 'medal', 'sport']
        if any(indicator in full_text for indicator in athletic_indicators):
            sports_articles.append({
                'title': article.get('title'),
                'description': description,
                'desc_length': len(description)
            })

# Find the sports article with the longest description
if sports_articles:
    longest = max(sports_articles, key=lambda x: x['desc_length'])
    result = longest['title']
else:
    # If no Olympic/sports articles found, check other sports
    general_sports = []
    sports_terms = ['football', 'basketball', 'baseball', 'soccer', 'tennis', 'golf', 'hockey']

    for article in articles_data:
        title = article.get('title', '').lower()
        desc = article.get('description', '').lower()
        description = article.get('description', '')

        if any(sport in title or sport in desc for sport in sports_terms):
            # Add additional context check
            if any(context in title or context in desc for context in ['coach', 'player', 'team', 'game', 'championship']):
                general_sports.append({
                    'title': article.get('title'),
                    'description': description,
                    'desc_length': len(description)
                })

    if general_sports:
        longest = max(general_sports, key=lambda x: x['desc_length'])
        result = longest['title']
    else:
        result = "No sports articles found"

print('__RESULT__:')
print(json.dumps(result))"}

